description:
## Overview
Build automatic solution mining that extracts reusable solutions, patterns, and learnings from agent session transcripts.

## Background
Agent sessions contain valuable problem-solving knowledge that currently gets lost. Solution mining automatically identifies successful problem resolutions and extracts them into the knowledge base.

## Mining Pipeline
```
┌─────────────────────────────────────────────────────────────┐
│                    Solution Mining Pipeline                  │
├─────────────────────────────────────────────────────────────┤
│  1. Session Selection  → Find completed successful sessions │
│  2. Transcript Analysis → Identify problem-solution pairs   │
│  3. Solution Extraction → Extract reusable patterns         │
│  4. Quality Scoring    → Rank by usefulness                 │
│  5. Knowledge Storage  → Store in knowledge base            │
│  6. Deduplication      → Merge similar solutions            │
└─────────────────────────────────────────────────────────────┘
```

## Session Selection
```rust
pub struct SessionSelector {
    store: Arc<VcStore>,
}

impl SessionSelector {
    /// Find sessions worth mining
    pub async fn select_candidates(&self, since: DateTime<Utc>) -> Result<Vec<SessionCandidate>> {
        self.store.query_vec::<SessionCandidate>(r#"
            SELECT 
                s.session_id,
                s.project,
                s.started_at,
                s.ended_at,
                s.model,
                COUNT(DISTINCT e.error_type) as error_count,
                COUNT(DISTINCT r.resolution_id) as resolution_count
            FROM cass_sessions s
            LEFT JOIN session_errors e ON s.session_id = e.session_id
            LEFT JOIN session_resolutions r ON s.session_id = r.session_id
            WHERE s.ended_at IS NOT NULL
              AND s.ended_at > ?
              AND s.outcome = "success"
              AND NOT EXISTS (SELECT 1 FROM mined_sessions WHERE session_id = s.session_id)
            ORDER BY resolution_count DESC, s.ended_at DESC
            LIMIT 100
        "#).bind(since).await
    }
}
```

## Transcript Analysis
```rust
pub struct TranscriptAnalyzer {
    llm: Arc<LlmClient>,
}

impl TranscriptAnalyzer {
    /// Analyze transcript for problem-solution pairs
    pub async fn analyze(&self, transcript: &str) -> Result<Vec<ProblemSolutionPair>> {
        let prompt = format!(r#"
            Analyze this agent session transcript and identify problem-solution pairs.

            For each problem solved in the session:
            1. Describe the problem clearly
            2. Describe the solution that worked
            3. Identify key insights or patterns
            4. Rate the solution quality (1-5)
            5. List relevant tags

            Return JSON array of:
            {{
                "problem": "description",
                "solution": "description",
                "insights": ["insight1", "insight2"],
                "code_snippets": ["snippet1"],
                "quality": 4,
                "tags": ["rust", "error-handling"]
            }}

            Transcript:
            {}
        "#, transcript);

        let response = self.llm.complete(&prompt).await?;
        let pairs: Vec<ProblemSolutionPair> = serde_json::from_str(&response)?;

        Ok(pairs)
    }
}
```

## Solution Extraction
```rust
pub struct SolutionExtractor {
    analyzer: TranscriptAnalyzer,
    store: Arc<VcStore>,
}

impl SolutionExtractor {
    /// Extract and store solutions from a session
    pub async fn extract(&self, session_id: &str) -> Result<Vec<KnowledgeEntry>> {
        // Get session transcript
        let transcript = self.store.get_session_transcript(session_id).await?;

        // Analyze for problem-solution pairs
        let pairs = self.analyzer.analyze(&transcript).await?;

        let mut entries = Vec::new();

        for pair in pairs {
            if pair.quality >= 3 {  // Only keep quality solutions
                let entry = KnowledgeEntry {
                    entry_type: EntryType::Solution,
                    title: self.generate_title(&pair),
                    summary: pair.problem.clone(),
                    content: self.format_solution(&pair),
                    source_session_id: Some(session_id.to_string()),
                    tags: pair.tags,
                    usefulness_score: pair.quality as f64 / 5.0,
                    ..Default::default()
                };

                // Check for duplicates before storing
                if !self.is_duplicate(&entry).await? {
                    self.store.insert_knowledge_entry(&entry).await?;
                    entries.push(entry);
                }
            }
        }

        // Mark session as mined
        self.store.mark_session_mined(session_id).await?;

        Ok(entries)
    }

    fn format_solution(&self, pair: &ProblemSolutionPair) -> String {
        let mut content = String::new();

        content.push_str("## Problem\n");
        content.push_str(&pair.problem);
        content.push_str("\n\n## Solution\n");
        content.push_str(&pair.solution);

        if !pair.insights.is_empty() {
            content.push_str("\n\n## Key Insights\n");
            for insight in &pair.insights {
                content.push_str(&format!("- {}\n", insight));
            }
        }

        if !pair.code_snippets.is_empty() {
            content.push_str("\n\n## Code Examples\n");
            for snippet in &pair.code_snippets {
                content.push_str(&format!("```\n{}\n```\n", snippet));
            }
        }

        content
    }
}
```

## Mining Scheduler
```rust
pub struct MiningScheduler {
    extractor: SolutionExtractor,
    selector: SessionSelector,
}

impl MiningScheduler {
    /// Run mining on a schedule
    pub async fn run_scheduled(&self) {
        let mut interval = tokio::time::interval(Duration::from_hours(1));

        loop {
            interval.tick().await;

            let since = Utc::now() - chrono::Duration::hours(24);
            match self.selector.select_candidates(since).await {
                Ok(candidates) => {
                    for candidate in candidates.into_iter().take(10) {
                        if let Err(e) = self.extractor.extract(&candidate.session_id).await {
                            tracing::error!("Mining failed for {}: {}", candidate.session_id, e);
                        }
                    }
                }
                Err(e) => tracing::error!("Candidate selection failed: {}", e),
            }
        }
    }
}
```

## Acceptance Criteria
- [ ] Session selection finds unmined successful sessions
- [ ] LLM analysis extracts problem-solution pairs
- [ ] Solutions formatted with problem, solution, insights, code
- [ ] Quality scoring filters low-quality extractions
- [ ] Deduplication prevents redundant entries
- [ ] Scheduled mining runs automatically
- [ ] Mining status tracked per session
- [ ] Manual trigger available via CLI

## Testing & Logging
- Deterministic unit tests with fixed seeds/time where applicable.
- Regression tests against fixture datasets.
- Safety tests: no side effects without allowlist/approval.
- E2E: scenario scripts under tests/e2e/system with JSON summaries and log artifacts.

## Overview
Build automatic playbook generation that creates Guardian playbooks from observed successful remediation patterns.

## Background
When operators manually resolve issues (rate limits, stuck agents, errors), their actions can be captured and converted into automated playbooks for future similar situations.

## Playbook Generation Pipeline
```
┌─────────────────────────────────────────────────────────────┐
│                Playbook Generation Pipeline                  │
├─────────────────────────────────────────────────────────────┤
│  1. Event Detection    → Alert fired + manual resolution    │
│  2. Action Capture     → Record operator actions taken      │
│  3. Pattern Recognition → Identify repeated patterns        │
│  4. Playbook Draft     → Generate playbook from pattern     │
│  5. Validation         → Test playbook safely               │
│  6. Approval           → Human review before activation     │
└─────────────────────────────────────────────────────────────┘
```

## Action Capture
```rust
pub struct ActionCapture {
    store: Arc<VcStore>,
}

impl ActionCapture {
    /// Capture actions taken after an alert
    pub async fn capture_resolution(
        &self,
        alert_id: i64,
        actions: Vec<CapturedAction>,
        outcome: ResolutionOutcome,
    ) -> Result<Resolution> {
        let alert = self.store.get_alert(alert_id).await?;

        let resolution = Resolution {
            alert_id,
            alert_type: alert.rule_id.clone(),
            trigger_context: alert.context.clone(),
            actions: actions.clone(),
            outcome,
            captured_at: Utc::now(),
        };

        self.store.insert_resolution(&resolution).await?;

        // Check if we have enough similar resolutions for pattern detection
        self.check_pattern_threshold(&alert.rule_id).await?;

        Ok(resolution)
    }
}

#[derive(Debug, Serialize, Deserialize)]
pub enum CapturedAction {
    Command { cmd: String, args: Vec<String>, success: bool },
    AccountSwitch { from: String, to: String },
    ProcessKill { pid: u32, name: String },
    ConfigChange { key: String, old: String, new: String },
    ServiceRestart { name: String },
    Custom { description: String, metadata: Value },
}
```

## Pattern Recognition
```rust
pub struct PatternRecognizer {
    store: Arc<VcStore>,
    llm: Arc<LlmClient>,
}

impl PatternRecognizer {
    /// Find patterns in successful resolutions
    pub async fn find_patterns(&self, alert_type: &str) -> Result<Vec<ResolutionPattern>> {
        // Get successful resolutions for this alert type
        let resolutions = self.store.query_vec::<Resolution>(r#"
            SELECT * FROM resolutions
            WHERE alert_type = ?
              AND outcome = "success"
            ORDER BY captured_at DESC
            LIMIT 50
        "#).bind(alert_type).await?;

        if resolutions.len() < 3 {
            return Ok(vec![]);  // Not enough data
        }

        // Use LLM to identify common patterns
        let prompt = format!(r#"
            Analyze these successful resolutions for the alert type "{}" and identify common patterns.

            Resolutions:
            {}

            For each pattern found:
            1. Describe the pattern
            2. List the common steps
            3. Identify required conditions
            4. Estimate confidence (0-1)

            Return JSON array of patterns.
        "#, alert_type, serde_json::to_string_pretty(&resolutions)?);

        let response = self.llm.complete(&prompt).await?;
        let patterns: Vec<ResolutionPattern> = serde_json::from_str(&response)?;

        Ok(patterns)
    }
}

#[derive(Debug, Serialize, Deserialize)]
pub struct ResolutionPattern {
    pub description: String,
    pub steps: Vec<PatternStep>,
    pub conditions: Vec<String>,
    pub confidence: f64,
    pub sample_count: usize,
}
```

## Playbook Draft Generation
```rust
pub struct PlaybookGenerator {
    recognizer: PatternRecognizer,
    store: Arc<VcStore>,
}

impl PlaybookGenerator {
    /// Generate a playbook from a recognized pattern
    pub fn generate_from_pattern(&self, pattern: &ResolutionPattern, alert_type: &str) -> PlaybookDraft {
        let steps: Vec<PlaybookStep> = pattern.steps.iter().map(|s| {
            match s {
                PatternStep::Command { cmd, args } => PlaybookStep::Command {
                    cmd: cmd.clone(),
                    args: args.clone(),
                    timeout_seconds: 30,
                    allow_failure: false,
                },
                PatternStep::AccountSwitch { strategy } => PlaybookStep::SwitchAccount {
                    program: "auto".into(),
                    strategy: strategy.clone(),
                },
                PatternStep::Wait { seconds } => PlaybookStep::Wait { seconds: *seconds },
                PatternStep::Notify { message } => PlaybookStep::Notify {
                    channel: "tui".into(),
                    message: message.clone(),
                },
            }
        }).collect();

        PlaybookDraft {
            playbook_id: format!("auto-{}-{}", alert_type, Uuid::new_v4()),
            name: format!("Auto-generated: {}", pattern.description),
            description: format!(
                "Automatically generated from {} successful resolutions. Confidence: {:.0}%",
                pattern.sample_count,
                pattern.confidence * 100.0
            ),
            trigger: PlaybookTrigger::OnAlert { rule_id: alert_type.to_string() },
            steps,
            requires_approval: true,  // Always require approval for auto-generated
            source_pattern: pattern.clone(),
            status: DraftStatus::PendingReview,
        }
    }

    /// Generate playbooks for all alert types with enough data
    pub async fn generate_all(&self) -> Result<Vec<PlaybookDraft>> {
        let alert_types = self.store.query_vec::<String>(
            "SELECT DISTINCT alert_type FROM resolutions WHERE outcome = \"success\""
        ).await?;

        let mut drafts = Vec::new();

        for alert_type in alert_types {
            let patterns = self.recognizer.find_patterns(&alert_type).await?;

            for pattern in patterns {
                if pattern.confidence >= 0.7 && pattern.sample_count >= 3 {
                    let draft = self.generate_from_pattern(&pattern, &alert_type);
                    self.store.insert_playbook_draft(&draft).await?;
                    drafts.push(draft);
                }
            }
        }

        Ok(drafts)
    }
}
```

## Validation & Approval
```rust
pub struct PlaybookValidator {
    store: Arc<VcStore>,
}

impl PlaybookValidator {
    /// Validate a playbook draft before activation
    pub async fn validate(&self, draft: &PlaybookDraft) -> Result<ValidationResult> {
        let mut issues = Vec::new();

        // Check for dangerous commands
        for step in &draft.steps {
            if let PlaybookStep::Command { cmd, args, .. } = step {
                if is_dangerous_command(cmd, args) {
                    issues.push(ValidationIssue::DangerousCommand(cmd.clone()));
                }
            }
        }

        // Check trigger condition exists
        if let PlaybookTrigger::OnAlert { rule_id } = &draft.trigger {
            if !self.store.alert_rule_exists(rule_id).await? {
                issues.push(ValidationIssue::InvalidTrigger(rule_id.clone()));
            }
        }

        // Check step feasibility
        for step in &draft.steps {
            if let Err(e) = self.validate_step(step).await {
                issues.push(ValidationIssue::InvalidStep(e.to_string()));
            }
        }

        Ok(ValidationResult {
            valid: issues.is_empty(),
            issues,
            recommendations: self.generate_recommendations(draft),
        })
    }

    /// Approve and activate a playbook
    pub async fn approve(&self, draft_id: &str, approver: &str) -> Result<Playbook> {
        let draft = self.store.get_playbook_draft(draft_id).await?;

        // Validate first
        let validation = self.validate(&draft).await?;
        if !validation.valid {
            return Err(Error::ValidationFailed(validation.issues));
        }

        // Convert to active playbook
        let playbook = Playbook::from_draft(draft, approver);
        self.store.insert_playbook(&playbook).await?;
        self.store.mark_draft_approved(draft_id, approver).await?;

        Ok(playbook)
    }
}
```

## Acceptance Criteria
- [ ] Action capture records operator remediation steps
- [ ] Pattern recognition finds common resolution sequences
- [ ] Playbook drafts generated from patterns
- [ ] Confidence threshold filters low-quality patterns
- [ ] Validation checks for dangerous commands
- [ ] Approval workflow before activation
- [ ] Generated playbooks marked as auto-generated
- [ ] Audit trail links playbooks to source patterns

