## Overview
Build an A/B testing framework that enables controlled experiments with different agent configurations, prompts, and settings.

## Background
To optimize agent performance, we need to scientifically compare different configurations. A/B testing provides the framework for running controlled experiments and measuring statistically significant differences.

## Data Model (DuckDB Schema)
```sql
CREATE TABLE experiments (
    experiment_id VARCHAR PRIMARY KEY,
    name VARCHAR NOT NULL,
    description TEXT,
    hypothesis VARCHAR,
    status VARCHAR NOT NULL,              -- draft, running, paused, completed
    started_at TIMESTAMP,
    ended_at TIMESTAMP,
    target_sample_size INTEGER,
    actual_sample_size INTEGER DEFAULT 0,
    primary_metric VARCHAR NOT NULL,      -- What we are measuring
    secondary_metrics VARCHAR[],
    created_at TIMESTAMP DEFAULT now(),
    created_by VARCHAR
);

CREATE TABLE experiment_variants (
    variant_id VARCHAR PRIMARY KEY,
    experiment_id VARCHAR REFERENCES experiments(experiment_id),
    name VARCHAR NOT NULL,                -- "control", "variant_a", "variant_b"
    is_control BOOLEAN DEFAULT FALSE,
    config JSON NOT NULL,                 -- The configuration for this variant
    traffic_weight FLOAT DEFAULT 1.0,     -- Relative traffic allocation
    sample_count INTEGER DEFAULT 0
);

CREATE TABLE experiment_assignments (
    id INTEGER PRIMARY KEY,
    experiment_id VARCHAR REFERENCES experiments(experiment_id),
    variant_id VARCHAR REFERENCES experiment_variants(variant_id),
    session_id VARCHAR NOT NULL,
    assigned_at TIMESTAMP DEFAULT now(),
    UNIQUE (experiment_id, session_id)
);

CREATE TABLE experiment_observations (
    id INTEGER PRIMARY KEY,
    experiment_id VARCHAR REFERENCES experiments(experiment_id),
    variant_id VARCHAR REFERENCES experiment_variants(variant_id),
    session_id VARCHAR NOT NULL,
    metric_name VARCHAR NOT NULL,
    metric_value FLOAT NOT NULL,
    observed_at TIMESTAMP DEFAULT now()
);

CREATE TABLE experiment_results (
    experiment_id VARCHAR PRIMARY KEY REFERENCES experiments(experiment_id),
    computed_at TIMESTAMP,
    winner_variant VARCHAR,
    confidence_level FLOAT,
    primary_metric_lift FLOAT,            -- % improvement over control
    is_significant BOOLEAN,
    full_results JSON                     -- Detailed stats
);
```

