## Experiment Manager
```rust
pub struct ExperimentManager {
    store: Arc<VcStore>,
}

impl ExperimentManager {
    /// Create a new experiment
    pub async fn create(&self, config: ExperimentConfig) -> Result<Experiment> {
        // Validate config
        self.validate_config(&config)?;

        // Store experiment
        let experiment = Experiment::from_config(config);
        self.store.insert_experiment(&experiment).await?;

        // Create variants
        for variant in &experiment.variants {
            self.store.insert_variant(variant).await?;
        }

        Ok(experiment)
    }

    /// Start an experiment
    pub async fn start(&self, experiment_id: &str) -> Result<()> {
        let mut experiment = self.store.get_experiment(experiment_id).await?;

        if experiment.status != ExperimentStatus::Draft {
            return Err(Error::InvalidState("Can only start draft experiments"));
        }

        experiment.status = ExperimentStatus::Running;
        experiment.started_at = Some(Utc::now());

        self.store.update_experiment(&experiment).await?;

        tracing::info!("Started experiment: {}", experiment_id);
        Ok(())
    }

    /// Assign a session to an experiment variant
    pub async fn assign(&self, experiment_id: &str, session_id: &str) -> Result<VariantConfig> {
        let experiment = self.store.get_experiment(experiment_id).await?;

        if experiment.status != ExperimentStatus::Running {
            return Err(Error::ExperimentNotRunning);
        }

        // Check if already assigned
        if let Some(existing) = self.store.get_assignment(experiment_id, session_id).await? {
            return self.store.get_variant(&existing.variant_id).await;
        }

        // Weighted random assignment
        let variant = self.select_variant(&experiment)?;

        let assignment = Assignment {
            experiment_id: experiment_id.to_string(),
            variant_id: variant.variant_id.clone(),
            session_id: session_id.to_string(),
            assigned_at: Utc::now(),
        };

        self.store.insert_assignment(&assignment).await?;
        self.store.increment_variant_count(&variant.variant_id).await?;

        Ok(variant.config)
    }

    fn select_variant(&self, experiment: &Experiment) -> Result<&Variant> {
        let total_weight: f64 = experiment.variants.iter().map(|v| v.traffic_weight).sum();
        let mut rng = rand::thread_rng();
        let roll: f64 = rng.gen::<f64>() * total_weight;

        let mut cumulative = 0.0;
        for variant in &experiment.variants {
            cumulative += variant.traffic_weight;
            if roll <= cumulative {
                return Ok(variant);
            }
        }

        Ok(experiment.variants.last().unwrap())
    }
}
```

## Metric Collection
```rust
pub struct MetricCollector {
    store: Arc<VcStore>,
}

impl MetricCollector {
    /// Record an observation for an experiment
    pub async fn record(&self, session_id: &str, metric: Metric, value: f64) -> Result<()> {
        // Find experiments this session is assigned to
        let assignments = self.store.get_session_assignments(session_id).await?;

        for assignment in assignments {
            let experiment = self.store.get_experiment(&assignment.experiment_id).await?;

            // Check if this metric is relevant
            let is_relevant = experiment.primary_metric == metric
                || experiment.secondary_metrics.contains(&metric);

            if is_relevant {
                let observation = Observation {
                    experiment_id: assignment.experiment_id,
                    variant_id: assignment.variant_id,
                    session_id: session_id.to_string(),
                    metric_name: metric.name(),
                    metric_value: value,
                    observed_at: Utc::now(),
                };

                self.store.insert_observation(&observation).await?;
            }
        }

        Ok(())
    }
}
```

## Statistical Analysis
```rust
pub struct ExperimentAnalyzer {
    store: Arc<VcStore>,
}

impl ExperimentAnalyzer {
    /// Analyze experiment results
    pub async fn analyze(&self, experiment_id: &str) -> Result<ExperimentResults> {
        let experiment = self.store.get_experiment(experiment_id).await?;
        let variants = self.store.get_variants(experiment_id).await?;

        let control = variants.iter().find(|v| v.is_control)
            .ok_or(Error::NoControl)?;

        let mut results = ExperimentResults {
            experiment_id: experiment_id.to_string(),
            computed_at: Utc::now(),
            variant_stats: Vec::new(),
            winner_variant: None,
            confidence_level: 0.0,
            is_significant: false,
        };

        // Compute stats for each variant
        for variant in &variants {
            let observations = self.store.get_observations(
                experiment_id,
                &variant.variant_id,
                &experiment.primary_metric.name()
            ).await?;

            let stats = VariantStats {
                variant_id: variant.variant_id.clone(),
                sample_size: observations.len(),
                mean: stats::mean(&observations),
                std_dev: stats::std_dev(&observations),
                confidence_interval: stats::confidence_interval(&observations, 0.95),
            };

            results.variant_stats.push(stats);
        }

        // Compare variants to control using t-test
        let control_stats = results.variant_stats.iter()
            .find(|s| s.variant_id == control.variant_id)
            .unwrap();

        for stats in &results.variant_stats {
            if stats.variant_id != control.variant_id {
                let (t_stat, p_value) = stats::two_sample_t_test(
                    control_stats,
                    stats
                );

                if p_value < experiment.significance_threshold {
                    if stats.mean > control_stats.mean {
                        // This variant is significantly better
                        let lift = (stats.mean - control_stats.mean) / control_stats.mean;
                        if results.winner_variant.is_none() || lift > results.primary_metric_lift {
                            results.winner_variant = Some(stats.variant_id.clone());
                            results.primary_metric_lift = lift;
                            results.confidence_level = 1.0 - p_value;
                            results.is_significant = true;
                        }
                    }
                }
            }
        }

        // Store results
        self.store.upsert_results(&results).await?;

        Ok(results)
    }
}
```

## Acceptance Criteria
- [ ] Experiments created with control and variant(s)
- [ ] Weighted random assignment to variants
- [ ] Metric collection for assigned sessions
- [ ] Statistical analysis with t-test
- [ ] Significance detection with configurable threshold
- [ ] Early stopping on significance (optional)
- [ ] Results visualization in TUI/web
- [ ] Experiment lifecycle management (draft/running/paused/completed)

