pub struct CaamCollector;

#[async_trait]
impl Collector for CaamCollector {
    fn name(&self) -> &'static str { "caam" }
    fn schema_version(&self) -> u32 { 1 }
    fn required_tool(&self) -> Option<&'static str> { Some("caam") }

    async fn collect(&self, ctx: &CollectContext) -> CollectResult {
        let collected_at = Utc::now();
        let mut rows = vec![];
        let mut warnings = vec![];

        // Get limits
        if let Ok(output) = ctx.executor.run_timeout("caam limits --format json", ctx.timeout).await {
            if let Ok(limits) = serde_json::from_str::<CaamLimitsOutput>(&output) {
                for provider in &limits.providers {
                    for profile in &provider.profiles {
                        rows.push(serde_json::json!({
                            "machine_id": ctx.machine_id.as_str(),
                            "collected_at": collected_at.to_rfc3339(),
                            "provider": provider.provider,
                            "profile": profile.name,
                            "window": profile.window,
                            "utilization_pct": profile.utilization_percent,
                            "resets_at": profile.resets_at,
                            "raw_json": serde_json::to_string(profile).unwrap_or_default(),
                        }));
                    }
                }
            }
        }

        // Get status
        if let Ok(output) = ctx.executor.run_timeout("caam status --json", ctx.timeout).await {
            if let Ok(status) = serde_json::from_str::<CaamStatusOutput>(&output) {
                for tool in &status.tools {
                    rows.push(serde_json::json!({
                        "table": "account_profile_snapshots",
                        "machine_id": ctx.machine_id.as_str(),
                        "collected_at": collected_at.to_rfc3339(),
                        "tool": tool.tool,
                        "active_profile": tool.active_profile,
                        "health_expires_at": tool.health_expires_at,
                        "raw_json": serde_json::to_string(tool).unwrap_or_default(),
                    }));
                }
            }
        }

        CollectResult {
            rows: vec![
                RowBatch { table: "account_limits_snapshots", rows: rows.clone() },
                RowBatch { table: "account_profile_snapshots", rows },
            ],
            ..Default::default()
        }
    }
}
