                        serde_json::json!({
                            "machine_id": ctx.machine_id.as_str(),
                            "collected_at": collected_at.to_rfc3339(),
                            "metric_name": "total_messages",
                            "metric_value": stats.total_messages,
                            "dimensions_json": "{}",
                        }),
                    ],
                });

                // Store per-agent breakdown
                for (agent, count) in &stats.by_agent {
                    rows.push(RowBatch {
                        table: "cass_stats_snapshots",
                        rows: vec![serde_json::json!({
                            "machine_id": ctx.machine_id.as_str(),
                            "collected_at": collected_at.to_rfc3339(),
                            "metric_name": "sessions_by_agent",
                            "metric_value": count,
                            "dimensions_json": format!(r#"{{"agent":"{}"}}"#, agent),
                        })],
                    });
                }
            }
        }

        CollectResult { rows, ..Default::default() }
    }
}
