## Overview
Build Agent DNA - behavioral fingerprints that characterize agent performance patterns and preferences.

## Background
Different agents (and different configurations of the same agent) exhibit distinct behavioral patterns: token usage, error rates, preferred tools, coding styles. Agent DNA captures these patterns to enable comparison, optimization, and anomaly detection.

## Data Model (DuckDB Schema)
```sql
CREATE TABLE agent_dna (
    dna_id VARCHAR PRIMARY KEY,
    agent_program VARCHAR NOT NULL,       -- claude-code, codex, gemini
    agent_model VARCHAR NOT NULL,         -- opus-4.5, gpt4, etc.
    configuration_hash VARCHAR,           -- Hash of relevant config
    computed_at TIMESTAMP DEFAULT now(),

    -- Token patterns
    avg_tokens_per_turn FLOAT,
    avg_input_output_ratio FLOAT,
    token_variance FLOAT,

    -- Error patterns
    error_rate FLOAT,
    common_error_types JSON,              -- {"parse_error": 0.3, "timeout": 0.1}
    recovery_rate FLOAT,                  -- How often errors are recovered

    -- Tool usage
    tool_preferences JSON,                -- {"Read": 0.4, "Edit": 0.3, "Bash": 0.2}
    tool_success_rates JSON,              -- Per-tool success rate
    avg_tools_per_task FLOAT,

    -- Timing patterns
    avg_response_time_ms FLOAT,
    p95_response_time_ms FLOAT,
    time_of_day_distribution JSON,        -- Hourly activity pattern

    -- Task patterns  
    avg_task_completion_time_mins FLOAT,
    task_success_rate FLOAT,
    complexity_handling JSON,             -- Success by task complexity

    -- Session patterns
    avg_session_duration_mins FLOAT,
    avg_turns_per_session FLOAT,
    session_abandonment_rate FLOAT,

    -- Embedding for similarity search
    dna_embedding FLOAT[128]
);

CREATE TABLE dna_history (
    id INTEGER PRIMARY KEY,
    dna_id VARCHAR REFERENCES agent_dna(dna_id),
    computed_at TIMESTAMP,
