```

## Implementation (vc_collect/src/ssh.rs)
```rust
use russh::{client, ChannelMsg};
use russh_keys::key;

pub struct SshRunner {
    connections: DashMap<String, Arc<SshSession>>,
    config: SshConfig,
}

pub struct SshConfig {
    pub connect_timeout: Duration,
    pub command_timeout: Duration,
    pub max_retries: u32,
    pub keepalive_interval: Duration,
}

impl SshRunner {
    pub async fn new(config: SshConfig) -> Result<Self>;

    /// Execute a command on a remote machine
    pub async fn exec(
        &self,
        machine: &Machine,
        cmd: &str,
    ) -> Result<CommandOutput> {
        let session = self.get_or_connect(machine).await?;
        let channel = session.channel_open_session().await?;
        channel.exec(true, cmd).await?;

        let mut stdout = Vec::new();
        let mut stderr = Vec::new();
        let mut exit_code = None;

        loop {
            match channel.wait().await {
                Some(ChannelMsg::Data { data }) => stdout.extend_from_slice(&data),
                Some(ChannelMsg::ExtendedData { data, .. }) => stderr.extend_from_slice(&data),
                Some(ChannelMsg::ExitStatus { exit_status }) => exit_code = Some(exit_status),
                Some(ChannelMsg::Eof) | None => break,
                _ => {}
            }
        }

        Ok(CommandOutput {
            stdout: String::from_utf8_lossy(&stdout).to_string(),
            stderr: String::from_utf8_lossy(&stderr).to_string(),
            exit_code: exit_code.unwrap_or(0),
        })
    }

    /// Transfer file from remote to local
    pub async fn fetch_file(
        &self,
        machine: &Machine,
        remote_path: &str,
        local_path: &Path,
    ) -> Result<()>;

    /// Check if connection is alive
    pub async fn ping(&self, machine: &Machine) -> Result<bool>;
}

pub struct CommandOutput {
    pub stdout: String,
    pub stderr: String,
    pub exit_code: u32,
}
```

## Connection Management
```rust
impl SshRunner {
    async fn get_or_connect(&self, machine: &Machine) -> Result<Arc<SshSession>> {
        // Check pool first
        if let Some(session) = self.connections.get(&machine.machine_id) {
            if session.is_alive().await {
                return Ok(session.clone());
            }
        }

        // Create new connection
        let ssh_config = machine.ssh_config.as_ref()
            .ok_or_else(|| Error::NoSshConfig(machine.machine_id.clone()))?;

        let key = russh_keys::load_secret_key(&ssh_config.key_path, None)?;
        let config = client::Config::default();

        let session = client::connect(
            Arc::new(config),
            (ssh_config.host.as_str(), ssh_config.port),
            SshHandler,
        ).await?;

        session.authenticate_publickey(
            &ssh_config.user,
            Arc::new(key),
        ).await?;

        let session = Arc::new(session);
        self.connections.insert(machine.machine_id.clone(), session.clone());
        Ok(session)
    }
}
```

